mapper.sql:
tenant_id = #{tenantId}

    and (lower(topology_code) like concat('%', lower(#{keyword}), '%')
    or lower(topology_name) like concat('%', lower(#{keyword}), '%'))

and env_id = #{envId}

mapper.update:
update fp_topology set topology_code=#{topologyCode}, topology_name=#{topologyName}, env_id=#{envId},
description=#{description}, canvas_config_json=#{canvasConfigJson}, updated_at=#{updatedAt}
where tenant_id=#{tenantId} and id=#{id}
